mapper.select:
SELECT ${field} as ${alias},
    COUNT(*) as calls,
    COALESCE(SUM(usage_total_tokens), 0) as tokens,
    COALESCE(SUM(CASE WHEN credit_amount < 0 THEN -credit_amount ELSE 0 END), 0) as consumeCredits
FROM fs_lm_usage
${where}
GROUP BY ${field}
ORDER BY ${orderBy}
LIMIT ${limit}

SELECT ${field} as ${alias}, COUNT(*) as count
FROM fs_lm_usage
${where}
GROUP BY ${field}
ORDER BY ${orderBy}
